          {(function(){var raifCom=coms.filter(function(c){return c.product==="RAIF"&&(c.comStatus==="Hard"||c.comStatus==="Signed"||c.comStatus==="Funded");}).reduce(function(a,c){return a+(c.amount||0);},0);var raifAdj=cls.filter(function(c){return(c.vehicles||[]).indexOf("RAIF")>=0;}).reduce(function(a,c){return a+adjProb(c);},0);var raifInvested=(fr.calls||[]).reduce(function(a,cc){return a+(cc.items||[]).reduce(function(a2,it2){if(!it2.received)return a2;var cm=coms.find(function(c){return c.id===it2.comId;});return a2+(cm&&cm.product==="RAIF"?(it2.called||0):0);},0);},0);var capV=fr.fund.cap||0;var cMR=parseFloat((raifCom/1e6).toFixed(1));var iMR=parseFloat((raifInvested/1e6).toFixed(1));var uMR=(cMR-iMR).toFixed(1);var aMR=parseFloat((raifAdj/1e6).toFixed(1));var totMR=parseFloat((cMR+aMR).toFixed(1));var pctInvR=capV>0?parseFloat((raifInvested/capV*100).toFixed(1)):0;var pctUnR=capV>0?parseFloat(((raifCom-raifInvested)/capV*100).toFixed(1)):0;var pctA=capV>0?((raifAdj/capV)*100).toFixed(1):0;return <div><div style={{background:"rgba(255,255,255,0.1)",borderRadius:4,height:20,overflow:"hidden",display:"flex"}}>{iMR>0?<div style={{background:C.accent,height:"100%",width:(capV>0?Math.min(raifInvested/capV*100,100):0)+"%",display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}><span style={{fontSize:7,color:"#000",fontWeight:700,whiteSpace:"nowrap"}}>{"\u20ac"+iMR+"m"}</span></div>:null}{parseFloat(uMR)>0?<div style={{background:C.green,height:"100%",width:(capV>0?Math.max(0,raifCom-raifInvested)/capV*100:0)+"%",display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}><span style={{fontSize:7,color:"#000",fontWeight:700,whiteSpace:"nowrap"}}>{"\u20ac"+uMR+"m"}</span></div>:null}{aMR>0?<div style={{background:C.gold,height:"100%",width:(capV>0?Math.min(raifAdj/capV*100,100):0)+"%",display:"flex",alignItems:"center",justifyContent:"center",overflow:"hidden"}}><span style={{fontSize:7,color:"#000",fontWeight:700,whiteSpace:"nowrap"}}>{"\u20ac"+aMR+"m"}</span></div>:null}</div><div style={{color:C.red,fontSize:10,marginTop:4,fontWeight:700}}>{"\u20ac"+totMR+"m ("+(capV>0?(totMR*1e6/capV*100).toFixed(1):0)+"%) / "}<span style={{color:C.red,fontWeight:700}}>{fmtNum(fr.fund.cap)}</span></div><div style={{color:C.accent,fontSize:9,marginTop:2,fontWeight:600}}>Funded: {"\u20ac"+iMR+"m"} ({pctInvR}%)</div><div style={{color:C.green,fontSize:9,marginTop:1,fontWeight:600}}>Uncalled: {"\u20ac"+uMR+"m"} ({pctUnR}%)</div><div style={{color:C.gold,fontSize:9,marginTop:1,fontWeight:600}}>Adj. pipeline: {"\u20ac"+aMR+"m"} ({pctA}%)</div></div>;})()}
